/* ── ESTADO INTERNO ── */
let _assoc = null, _cat = 'Todas', _q = '', _view = 'map'; // 'map' por defecto
let _hintTimer = null;

/* ── UTILIDAD ── */
function _esc(s) {
  return (s || '').replace(/[&<>"']/g, c =>
    ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c])
  );
}

/* ── API PÚBLICA ── */
function openDir(key, subtitle) {
  _assoc = key; _cat = 'Todas'; _q = '';
  const listOnly = DIR_LIST_ONLY.includes(key);
  _view = listOnly ? 'list' : 'map';
  document.getElementById('dirTitle').textContent =
    'Directorio de Empresas — ' + key.replace('PuertoMogan', 'Puerto de Mogán');
  document.getElementById('dirSubtitle').textContent = subtitle;
  document.getElementById('dirSearch').value = '';
  document.getElementById('dirPanel').classList.toggle('view-map', _view === 'map');
  const toggleEl = document.getElementById('dirToggle');
  toggleEl.classList.toggle('on', _view === 'map');
  const switchEl = document.getElementById('dirViewSwitch');
  const hintEl = document.getElementById('dirViewHint');
  // Oculta el interruptor mapa/lista (incluidas sus etiquetas) cuando la
  // asociación no tiene datos de mapa
  switchEl.style.display = listOnly ? 'none' : '';
  hintEl.classList.remove('show');
  if (_hintTimer) clearTimeout(_hintTimer);
  if (!listOnly) {
    // Aviso emergente: informa de que el modo mapa es el predeterminado
    // y que se puede cambiar a lista para una mejor visualización.
    _hintTimer = setTimeout(() => hintEl.classList.add('show'), 350);
    setTimeout(() => hintEl.classList.remove('show'), 8000);
  }
  _buildFilters();
  _render();
  document.getElementById('dirOverlay').classList.add('active');
  document.body.style.overflow = 'hidden';
}

function closeDir() {
  document.getElementById('dirOverlay').classList.remove('active');
  document.body.style.overflow = '';
}

/* ── FILTROS ── */
function _buildFilters() {
  const items = DIR_DATA[_assoc] || [];
  const cats  = ['Todas', ...[...new Set(items.map(i => i.cat).filter(Boolean))].sort()];
  const area  = document.getElementById('dirFilters');
  const search = area.querySelector('#dirSearch');
  area.innerHTML = '';
  area.appendChild(search);
  cats.forEach(c => {
    const b = document.createElement('button');
    b.className = 'dir-cat-btn' + (c === _cat ? ' on' : '');
    b.textContent = c;
    b.onclick = () => { _cat = c; _buildFilters(); _render(); };
    area.appendChild(b);
  });
  search.oninput = e => { _q = e.target.value; _render(); };
}

/* ── INTERRUPTOR LISTA / MAPA (fijo en la cabecera del modal) ── */
function _setView(view) {
  // Si la asociación actual es "solo lista", nunca se permite cambiar a mapa.
  if (DIR_LIST_ONLY.includes(_assoc) && view === 'map') return;
  _view = view;
  const panel  = document.getElementById('dirPanel');
  const toggle = document.getElementById('dirToggle');
  panel.classList.toggle('view-map', _view === 'map');
  toggle.classList.toggle('on', _view === 'map');
  _render();
}

/* ── RENDER ── */
function _render() {
  const items    = DIR_DATA[_assoc] || [];
  const q        = _q.toLowerCase().trim();
  const filtered = items.filter(i => {
    if (_cat !== 'Todas' && i.cat !== _cat) return false;
    if (q && !([i.name, i.sector, i.dir].some(f => (f || '').toLowerCase().includes(q)))) return false;
    return true;
  });

  document.getElementById('dirCount').textContent =
    filtered.length + ' empresa' + (filtered.length !== 1 ? 's' : '') +
    (_cat !== 'Todas' ? ' en ' + _cat : '') +
    (q ? ' que contienen "' + _q + '"' : '');

  const grid = document.getElementById('dirGrid');
  const mapBox = document.getElementById('dirMap');

  /* Alterna visibilidad con una transición suave */
  if (_view === 'map') {
    grid.classList.add('dir-hidden');
    mapBox.classList.remove('dir-hidden');
    requestAnimationFrame(() => mapBox.classList.add('dir-visible'));
    grid.classList.remove('dir-visible');
    _renderMap(filtered);
  } else {
    mapBox.classList.remove('dir-visible');
    mapBox.classList.add('dir-hidden');
    grid.classList.remove('dir-hidden');
    requestAnimationFrame(() => grid.classList.add('dir-visible'));
  }

  if (!filtered.length) {
    grid.innerHTML = '<div class="dir-empty">No se encontraron empresas con los filtros seleccionados.</div>';
    return;
  }

  const PIN = `<svg viewBox="0 0 24 24"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>`;
  const TEL = `<svg viewBox="0 0 24 24"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 12 19.79 19.79 0 0 1 1.61 3.38 2 2 0 0 1 3.6 1.21h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L7.91 8.81a16 16 0 0 0 6.29 6.29l.96-.96a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 22 16.92z"/></svg>`;

  grid.innerHTML = filtered.map(i => {
    const icon = DIR_ICONS[i.cat] || DIR_ICONS['Comercio'];
    const dir  = i.dir && i.dir.toLowerCase() !== 'desconocido' ? i.dir : '';
    const tel  = i.tel && !['no tiene', 'desconocido', ''].includes(i.tel.toLowerCase()) ? i.tel : '';

    // Solo se construye el enlace a Google Maps si la empresa tiene una
    // dirección real; si no, no se muestra ningún enlace ni bloque de dirección.
    let dirBlock = '';
    if (dir) {
      const mq  = i.name + ', ' + dir + ', Gran Canaria, España';
      const url = 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(mq);
      dirBlock = `<div class="dir-card-dir">
        <span class="meta-icon">${PIN}</span>
        <a href="${url}" target="_blank" rel="noopener" title="Ver en Google Maps">${_esc(dir)}</a>
      </div>`;
    }

    return `<div class="dir-card">
      <div class="dir-card-icon">${icon}</div>
      <div class="dir-card-name">${_esc(i.name)}</div>
      <span class="dir-card-cat">${_esc(i.cat)}</span>
      ${i.sector ? `<div class="dir-card-sector">${_esc(i.sector)}</div>` : ''}
      ${dirBlock}
      ${tel ? `<div class="dir-card-tel"><span class="meta-icon">${TEL}</span>${_esc(tel)}</div>` : ''}
    </div>`;
  }).join('');
}

/* ── MAPA GEORREFERENCIADO ── */
function _renderMap(filtered) {
  const mapBox = document.getElementById('dirMap');
  const customEmbed = DIR_MAPS[_assoc];

  if (customEmbed) {
    // Mapa personalizado (Google My Maps) configurado por la asociación,
    // con todas las empresas como pines.
    mapBox.innerHTML = `<iframe src="${customEmbed}" loading="lazy" referrerpolicy="no-referrer-when-downgrade" allowfullscreen></iframe>`;
    return;
  }

  // Mapa de respaldo: centra la búsqueda en la zona de la asociación.
  // (No requiere clave de API, pero no puede marcar cada empresa como
  // un pin independiente; para eso, crea un mapa en Google My Maps y
  // añade su URL de inserción en DIR_MAPS al principio de este archivo).
  const zone = DIR_ZONES[_assoc] || 'Gran Canaria, España';
  const query = _cat !== 'Todas'
    ? _cat + ' en ' + zone
    : 'comercios y empresas en ' + zone;
  const src = 'https://www.google.com/maps?q=' + encodeURIComponent(query) + '&output=embed';
  mapBox.innerHTML = `<iframe src="${src}" loading="lazy" referrerpolicy="no-referrer-when-downgrade" allowfullscreen></iframe>`;
}

/* ── EVENTOS GLOBALES ── */
document.addEventListener('DOMContentLoaded', () => {
  document.getElementById('dirClose').onclick = closeDir;
  document.getElementById('dirOverlay').onclick = e => {
    if (e.target === e.currentTarget) closeDir();
  };
  document.getElementById('dirToggle').onclick = () => {
    document.getElementById('dirViewHint').classList.remove('show');
    _setView(_view === 'map' ? 'list' : 'map');
  };
  document.getElementById('dirViewHint').onclick = () => {
    document.getElementById('dirViewHint').classList.remove('show');
    _setView('list');
  };
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape') closeDir();
  });
});